(function () {
  'use strict';

  function back2top() {
    var $window = $(window);
    var $btn = $('#back-to-top');

    $window.on('scroll', function () {
      $window.scrollTop() > 50 ? $btn.fadeIn() : $btn.fadeOut();
    });

    $btn.on('click', function () {
      $window.scrollTop(0);
    });
  }

  function loadTooptip() {
    var tooltipTriggerList = document.querySelectorAll('[data-bs-toggle="tooltip"]');
    Array.prototype.slice.call(tooltipTriggerList).map(function (tooltipTriggerEl) {
      return new bootstrap.Tooltip(tooltipTriggerEl);
    });
  }

  function modeWatcher() {
    var $toggleElem = $('.mode-toggle');

    if ($toggleElem.length === 0) {
      return;
    }

    $toggleElem.off().on('click', function (e) {
      var $target = $(e.target);
      var $btn = $target.prop('tagName') === 'BUTTON' ? $target : $target.parent();

      modeToggle.flipMode();
      $btn.trigger('blur');
    });
  }

  function sidebarExpand() {
    var $body = $('body');
    var isExpanded = false;

    function toggle() {
      isExpanded === false ? $body.attr('sidebar-display', '') : $body.removeAttr('sidebar-display');
      isExpanded = !isExpanded;
    }

    $('#sidebar-trigger').on('click', toggle);
    $('#mask').on('click', toggle);
  }

  function initLocaleDatetime() {
    dayjs.locale($('html').attr('lang').substring(0, 2));
    dayjs.extend(window.dayjs_plugin_localizedFormat);

    $('[data-ts]').each(function () {
      var $this = $(this);
      var date = dayjs.unix(Number($this.attr('data-ts')));
      $this.text(date.format($this.attr('data-df')));
      $this.removeAttr('data-ts').removeAttr('data-df');

      if ($this.attr('data-bs-toggle') === 'tooltip') {
        $this.attr('data-bs-title', date.format('llll'));
        new bootstrap.Tooltip($this);
      }
    });
  }

  back2top();
  loadTooptip();
  modeWatcher();
  sidebarExpand();
  initLocaleDatetime();
})();
